fn q<T: Ord + Clone>(mut a: &mut [T]) {
    while a.len() > 24 {
        let (n, m, e) = (a.len(), a.len() / 2, a.len() - 1);
        if a[m] < a[0] { a.swap(0, m) }
        if a[e] < a[0] { a.swap(0, e) }
        if a[e] < a[m] { a.swap(m, e) }
        let (p, mut i, mut l, mut r) = (a[m].clone(), 0, 0, n);
        while i < r {
