                Ordering::Less => { a.swap(i, l); i += 1; l += 1 }
                Ordering::Greater => { r -= 1; a.swap(i, r) }
                _ => i += 1
            }
        }
        if l < n - r { q(&mut a[..l]); a = &mut a[r..] }
        else { q(&mut a[r..]); a = &mut a[..l] }
    }
    for i in 1..a.len() {
        let mut j = i;
        while j > 0 && a[j-1] > a[j] { a.swap(j-1, j); j -= 1 }
